INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Chair_Squat','Chair Squat','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'máquina','strength',ARRAY['To begin, first set the bar to a position that best matches your height. Once the bar is loaded, step under it and position it across the back of your shoulders.','Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs.','Move your feet forward about 18 inches in front of the bar. Position your legs using a shoulder width stance with the toes slightly pointed out. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position.','Slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper and lower leg breaks 90 degrees.','Begin to raise the bar as you exhale by pushing the floor with the heels of your feet, extending the knees and returning to the starting position.','Repeat for the recommended amount of repetitions.'],'To begin, first set the bar to a position that best matches your height. Once the bar is loaded, step under it and position it across the back of your shoulders. Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs. Move your feet forward about 18 inches in front of the bar. Position your legs using a shoulder width stance with the toes slightly pointed out. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position. Slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper and lower leg breaks 90 degrees. Begin to raise the bar as you exhale by pushing the floor with the heels of your feet, extending the knees and returning to the starting position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chair_Squat/0.jpg','exercisedb',true),('Chair_Upper_Body_Stretch','Chair Upper Body Stretch','hombros',ARRAY['bíceps','pecho'],'otro','stretching',ARRAY['Sit on the edge of a chair, gripping the back of it.','Straighten your arms, keeping your back straight, and pull your upper body forward so you feel a stretch. Hold for 20-30 seconds.'],'Sit on the edge of a chair, gripping the back of it. Straighten your arms, keeping your back straight, and pull your upper body forward so you feel a stretch. Hold for 20-30 seconds.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chair_Upper_Body_Stretch/0.jpg','exercisedb',true),('Chest_And_Front_Of_Shoulder_Stretch','Chest And Front Of Shoulder Stretch','pecho',ARRAY['hombros'],'otro','stretching',ARRAY['Start off by standing with your legs together, holding a bodybar or a broomstick.','Take a slightly wider than shoulder width grip on the pole and hold it in front of you with your palms facing down.','Carefully lift the pole up and behind your head.'],'Start off by standing with your legs together, holding a bodybar or a broomstick. Take a slightly wider than shoulder width grip on the pole and hold it in front of you with your palms facing down. Carefully lift the pole up and behind your head.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_And_Front_Of_Shoulder_Stretch/0.jpg','exercisedb',true),('Chest_Push_from_3_point_stance','Chest Push from 3 point stance','pecho',ARRAY['abdominales','hombros','tríceps'],'balón medicinal','plyometrics',ARRAY['Begin in a three point stance, squatted down with your back flat and one hand on the ground. Place the medicine ball directly in front of you.','To begin, take your first step as you pull the ball to your chest, positioning both hands to prepare for the throw.','As you execute the second step, explosively release the ball forward as hard as possible.'],'Begin in a three point stance, squatted down with your back flat and one hand on the ground. Place the medicine ball directly in front of you. To begin, take your first step as you pull the ball to your chest, positioning both hands to prepare for the throw. As you execute the second step, explosively release the ball forward as hard as possible.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Push_from_3_point_stance/0.jpg','exercisedb',true),('Chest_Push_multiple_response','Chest Push (multiple response)','pecho',ARRAY['abdominales','hombros','tríceps'],'balón medicinal','plyometrics',ARRAY['Begin in a kneeling position facing a wall or utilize a partner. Hold the ball with both hands tight into the chest.','Execute the pass by exploding forward and outward with the hips while pushing the ball as hard as possible.','Follow through by falling forward, catching yourself with your hands.','Immediately return to an upright position. Repeat for the desired number of repetitions.'],'Begin in a kneeling position facing a wall or utilize a partner. Hold the ball with both hands tight into the chest. Execute the pass by exploding forward and outward with the hips while pushing the ball as hard as possible. Follow through by falling forward, catching yourself with your hands. Immediately return to an upright position. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Push_multiple_response/0.jpg','exercisedb',true),('Chest_Push_single_response','Chest Push (single response)','pecho',ARRAY['abdominales','hombros','tríceps'],'balón medicinal','plyometrics',ARRAY['Begin in a kneeling position holding the medicine ball with both hands tightly into the chest.','Execute the pass by exploding forward and outward with the hips while pushing the ball as far as possible.','Follow through by falling forward, catching yourself with your hands.'],'Begin in a kneeling position holding the medicine ball with both hands tightly into the chest. Execute the pass by exploding forward and outward with the hips while pushing the ball as far as possible. Follow through by falling forward, catching yourself with your hands.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Push_single_response/0.jpg','exercisedb',true),('Chest_Push_with_Run_Release','Chest Push with Run Release','pecho',ARRAY['abdominales','hombros','tríceps'],'balón medicinal','plyometrics',ARRAY['Begin in an athletic stance with the knees bent, hips back, and back flat. Hold the medicine ball near your legs. This will be your starting position.','While taking your first step draw the medicine ball into your chest.','As you take the second step, explosively push the ball forward, immediately sprinting for 10 yards after the release. If you are really fast, you can catch your own pass!'],'Begin in an athletic stance with the knees bent, hips back, and back flat. Hold the medicine ball near your legs. This will be your starting position. While taking your first step draw the medicine ball into your chest. As you take the second step, explosively push the ball forward, immediately sprinting for 10 yards after the release. If you are really fast, you can catch your own pass!','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Push_with_Run_Release/0.jpg','exercisedb',true),('Chest_Stretch_on_Stability_Ball','Chest Stretch on Stability Ball','pecho',ARRAY[]::text[],'pelota de ejercicio','stretching',ARRAY['Get on your hands and knees next to an exercise ball.','Place your elbows on top of the ball, keeping your arm out to your side. This will be your starting position.','Lower your torso towards the floor, keeping your elbow on top of the ball. Hold the stretch for 20-30 seconds, and repeat with the other arm.'],'Get on your hands and knees next to an exercise ball. Place your elbows on top of the ball, keeping your arm out to your side. This will be your starting position. Lower your torso towards the floor, keeping your elbow on top of the ball. Hold the stretch for 20-30 seconds, and repeat with the other arm.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Stretch_on_Stability_Ball/0.jpg','exercisedb',true),('Childs_Pose','Child''s Pose','espalda baja',ARRAY['glúteos','espalda media'],NULL,'stretching',ARRAY['Get on your hands and knees, walk your hands in front of you.','Lower your buttocks down to sit on your heels. Let your arms drag along the floor as you sit back to stretch your entire spine.','Once you settle onto your heels, bring your hands next to your feet and relax. "breathe" into your back. Rest your forehead on the floor. Avoid this position if you have knee problems.'],'Get on your hands and knees, walk your hands in front of you. Lower your buttocks down to sit on your heels. Let your arms drag along the floor as you sit back to stretch your entire spine. Once you settle onto your heels, bring your hands next to your feet and relax. "breathe" into your back. Rest your forehead on the floor. Avoid this position if you have knee problems.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Childs_Pose/0.jpg','exercisedb',true),('Chin-Up','Chin-Up','dorsales',ARRAY['bíceps','antebrazos','espalda media'],'peso corporal','strength',ARRAY['Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.','As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.','As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement.','Repeat this motion for the prescribed amount of repetitions.'],'Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width. As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement. As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar. After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement. Repeat this motion for the prescribed amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chin-Up/0.jpg','exercisedb',true);